sql:
SELECT COUNT(DISTINCT trainee_id) AS total_trainees
FROM enrollments
WHERE status = 'completed';

external_knowledge:
- "Successful enrollments" imply that the program has at least one enrolled student;
- "Generated revenue" means the program has at least one transaction recorded;
- "Received positive feedback" indicates that the program has an average rating greater than 0, suggesting at least one rating has been given;
- "Rank based on their popularity, financial success, and trainee satisfaction" refers to the order of the results by the number of enrollments, total revenue, and average rating, respectively.

sql:
SELECT COUNT(*) 
FROM training_providers 
WHERE provider_name = 'Foreword Coffee';

SELECT training_provider_id, COUNT(program_id) AS total_programs
FROM training_programs
GROUP BY training_provider_id;

external_knowledge:
- 'Total amount paid' refers to the sum of all financial transactions associated with each trainee's enrollments;
- 'Trainee name' is the full name of the trainee as stored in the `trainees` table;
- The results are ordered by the total amount paid in descending order.

- 'blossomed like flowers' refers to programs that have been well-received by trainees;
- 'eager learners' refers to trainees who have enrolled in the programs;
- 'embarked on this educational journey' refers to the process of enrolling in and completing the training programs.

- "Most fertile fields" refers to the program categories with the highest total fees earned;
- "Yield of the harvest" represents the total fees earned by the training providers;
- "Garden" is a metaphor for the collection of training programs.

- "students" refers to individuals who have enrolled in the training programs;
- "shine" refers to the programs having a high number of enrollments;
- "schools of thought" is a metaphor for training programs.

- 'Total payments' refers to the sum of all 'payment' transactions for each program;
- 'Average rating' is calculated by averaging the ratings given by trainees in the feedback;
- 'Evaluation results' include the outcomes of the program evaluations, which are conducted to assess the effectiveness of the training programs.

- 'top three' refers to the highest average ratings;
- 'shining the brightest in the night sky' is a metaphor for the highest-rated programs;
- 'stars they have been awarded' refers to the ratings given by trainees.

- Active programs are those with a `program_status` of 'active';
- The `average_rating` is calculated from the ratings given by trainees;
- The `total_enrollments` represent the number of trainees enrolled in each program.

sql:
SELECT program_title
FROM training_programs
WHERE CAST(REPLACE(nett_fee, '.', '') AS REAL) = (
  SELECT MAX(CAST(REPLACE(nett_fee, '.', '') AS REAL))
  FROM training_programs
);

external_knowledge:
- "blossoming trainees" refers to trainees who have made payments;
- "watered the financial soil" refers to the financial transactions made by trainees;
- "seasoned trainers" refers to trainers who have conducted sessions;
- "tended to the sessions" refers to the sessions conducted by trainers.
